config.script:
let items = step_1.items;
let top_n = to_int("{{params.top_n}}");
let result = [];
let count = if items.len > top_n { top_n } else { items.len };
for i in 0..count {
    let item = items[i];
    let idx = i + 1;
    let title = if item.title != () { item.title.trim() } else { "" };
    let link = if item.link != () { item.link } else { "" };
    result.push([to_string(idx), title, link]);
}
